        return f'Users: {len(self.users)}, Logs: {len(self.logs)}'

def set_status(ticket, status_code):
    if status_code == 0:
        ticket['status'] = 'open'
    elif status_code == 1:
        ticket['status'] = 'in_progress'
    elif status_code == 2:
        ticket['status'] = 'resolved'
    elif status_code == 3:
        ticket['status'] = 'closed'

